import React from 'react';

interface GreetingProps {
  name: string;
  age?: number; // Optional prop
}

function Greeting({ name, age }: GreetingProps) {
  return (
    <div>
      <p>Salam, {name}!</p>
      {age && <p>Yaş: {age}</p>}
    </div>
  );
}

function App() {
  return <Greeting name="Aysel" age={20} />;
}

console.log('TypeScript ilə props komponenti yaradıldı');

import React, { useState } from 'react';

function Counter() {
  const [count, setCount] = useState<number>(0);

  return (
    <div>
      <p>Say: {count}</p>
      <button onClick={() => setCount(count + 1)}>Artır</button>
    </div>
  );
}

console.log('TypeScript ilə useState yaradıldı');

import React, { ChangeEvent } from 'react';

function InputExample() {
  const [text, setText] = React.useState<string>('');

  const handleChange = (e: ChangeEvent<HTMLInputElement>) => {
    setText(e.target.value);
  };

  return (
    <div>
      <input type="text" value={text} onChange={handleChange} />
      <p>Daxil edilən: {text}</p>
    </div>
  );
}

console.log('TypeScript ilə event tipləri yaradıldı');

import React from 'react';

interface ButtonProps {
  text: string;
  color?: string; // Optional
}

function Button({ text, color = 'blue' }: ButtonProps) {
  return <button style={{ backgroundColor: color }}>{text}</button>;
}

function App() {
  return (
    <div>
      <Button text="Klik et" />
      <Button text="Qırmızı" color="red" />
    </div>
  );
}

